"""A module that contains functions to transform python objects related to geo-referenced annotations and detections
"""

import numpy as np
import numpy.typing as npt

from geosat.tools.boundingboxes import OrientedDetectionBox


def compute_oriented_angle_2d(
    vector_a: npt.ArrayLike, vector_b: npt.ArrayLike
) -> float:
    """
    Returns the oriented angle to go from vector_a to vector_b
    :param vector_a: a 2D vector
    :param vector_b: a 2D vector
    :return: angle in radian between 0 and 2*pi
    """
    dot = np.dot(vector_a, vector_b)
    det = np.linalg.det(np.r_[np.atleast_2d(vector_a), np.atleast_2d(vector_b)])
    return np.arctan2(det, dot)


def convert_2d_coords_to_oriented_detection_box(
    coordinates: npt.NDArray[np.float64],
    score: float = 1.0,
    class_id: int = 0,
    class_name: str = "N/A",
) -> OrientedDetectionBox:
    if coordinates.shape[0] < 3:
        raise ValueError(
            f"At least 3 coordinates are needed to deduce the bounding box "
            f"extent but {coordinates.shape[0]} were found."
        )
    first_segment = coordinates[1] - coordinates[0]
    second_segment = coordinates[2] - coordinates[1]
    width = np.linalg.norm(first_segment)

    if np.dot(first_segment, second_segment) == 0:
        second_segment_projected = second_segment
    else:
        rotation_clockwise = np.array([[0, -1], [1, 0]])
        normal_vector = first_segment / width @ rotation_clockwise
        second_segment_projected = (
            np.dot(second_segment, normal_vector)
            / np.dot(normal_vector, normal_vector)
            * normal_vector
        )

    height = np.linalg.norm(second_segment_projected)
    v_x = np.array([1, 0])
    angle = compute_oriented_angle_2d(v_x, first_segment)
    angle_deg = np.rad2deg(angle)
    center = coordinates[0] + first_segment / 2 + second_segment_projected / 2

    return OrientedDetectionBox(
        center[0] - width / 2,
        center[1] - height / 2,
        center[0] + width / 2,
        center[1] + height / 2,
        angle=angle_deg,
        class_name=class_name,
        score=score,
        class_id=class_id,
    )
